source configuration\n  #########################################\n\n  # mysql\n  datasource:\n    dynamic:\n      datasource:\n        master:\n          driver-class-name: com.mysql.cj.jdbc.Driver\n          url: jdbc:mysql://localhost:3306/snowy-cloud?useUnicode=true&characterEncoding=utf-8&useSSL=false&allowPublicKeyRetrieval=true&nullCatalogMeansCurrent=true&useInformationSchema=true&rewriteBatchedStatements=true\n          username: root\n          password: 123456\n      strict: true\n\n  # oracle\n#  datasource:\n#    dynamic:\n#      datasource:\n#        master:\n#          driver-class-name: oracle.jdbc.driver.OracleDriver\n#          url: jdbc:oracle:thin:@//127.0.0.1:1521/XE?remarksReporting=true\n#          username: SNOWY\n#          password: 12345678\n#      strict: true\n\n  # mssql\n#  datasource:\n#    dynamic:\n#      datasource:\n#        master:\n#          driver-class-name: com.microsoft.sqlserver.jdbc.SQLServerDriver\n#          url: jdbc:sqlserver://localhost:1433;DatabaseName=SNOWY\n#          username: sa\n#          password: 12345678\n#      strict: true\n\n  # dm database\n#  datasource:\n#    dynamic:\n#      datasource:\n#        master:\n#          driver-class-name: dm.jdbc.driver.DmDriver\n#          url: jdbc:dm://localhost:5236/SYSDBA\n#          username: SYSDBA\n#          password: SYSDBA\n#      strict: true\n\n  # kingbase database\n#  datasource:\n#    dynamic:\n#      datasource:\n#        master:\n#          driver-class-name: com.kingbase8.Driver\n#          url: jdbc:kingbase8://localhost:54321/snowy\n#          username: SYSTEM\n#          password: 123456\n#      strict: true\n\n      # druid global configuration\n      public-key: MFwwDQYJKoZIhvcNAQEBBQADSwAwSAJBAMWiTVtdXFVrgFHDDKELZM0SywkWY3KjugN90eY5Sogon1j8Y0ClPF7nx3FuE7pAeBKiv7ChIS0vvx/59WUpKmUCAwEAAQ==\n      druid:\n        initial-size: 10\n        max-active: 80\n        min-idle: 10\n        max-wait: 60000\n        pool-prepared-statements: true\n        max-pool-prepared-statement-per-connection-size: 20\n        validation-query-timeout: 2000\n        test-on-borrow: false\n        test-on-return: false\n        test-while-idle: true\n        time-between-eviction-runs-millis: 6000\n        min-evictable-idle-time-millis: 300000\n        filters: stat\n        break-after-acquire-failure: false\n\n    # druid monitor configuration\n    druid:\n      stat-view-servlet:\n        enabled: true\n        login-username: admin\n        login-password: 123456\n        allow: \"\"\n\n  #########################################\n  # jackson configuration\n  #########################################\n  jackson:\n    time-zone: GMT+8\n    date-format: yyyy-MM-dd HH:mm:ss\n    locale: zh_CN\n\n  #########################################\n  # redis configuration\n  #########################################\n  data:\n    redis:\n      database: 1\n      host: 127.0.0.1\n      port: 6379\n      password:\n      timeout: 10s\n      lettuce:\n        pool:\n          max-active: 800\n          max-wait: -1ms\n          max-idle: 10\n          min-idle: 0\n\n#########################################\n# 开放所有endpoint，实际生产根据自身需要开放，出于安全考虑不建议全部开放\n#########################################\nmanagement:\n  endpoints:\n    web:\n      exposure:\n        include: \"*\"\n    health:\n      show-details: \"ALWAYS\"\n\n#########################################\n# mybatis-plus configuration\n#########################################\nmybatis-plus:\n  configuration:\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n  global-config:\n    banner: false\n    enable-sql-runner: true\n    db-config:\n      id-type: ASSIGN_ID\n      logic-delete-field: DELETE_FLAG\n      logic-delete-value: DELETED\n      logic-not-delete-value: NOT_DELETE\n  mapper-locations: classpath*:vip/xiaonuo/**/mapping/*.xml,com/bstek/**/mapping/*.xml\n  type-handlers-package: vip.xiaonuo.common.handler\n\n#########################################\n# easy-trans configuration\n#########################################\neasy-trans:\n  is-enable-redis: true\n  is-enable-global: true\n  is-enable-tile: true\n  is-enable-cloud: false\n\n#########################################\n# sa-token configuration\n#########################################\nsa-token:\n  token-name: token\n  timeout: 2592000\n  active-timeout: -1\n  is-concurrent: true\n  is-share: false\n  max-login-count: -1\n  token-style: random-32\n  is-log: false\n  is-print: false\n\n# sa-token alone-redis configuration\n  alone-redis:\n    database: 2\n    host: ${spring.data.redis.host}\n    port: ${spring.data.redis.port}\n    password: ${spring.data.redis.password}\n    timeout: ${spring.data.redis.timeout}\n    lettuce:\n      pool:\n        max-active: ${spring.data.redis.lettuce.pool.max-active}\n        max-wait: ${spring.data.redis.lettuce.pool.max-wait}\n        max-idle: ${spring.data.redis.lettuce.pool.max-idle}\n        min-idle: ${spring.data.redis.lettuce.pool.min-idle}\n\n  # sso configuration      \n  sso-client:\n    client: \n    auth-url: \n    signout-url: \n    push-url: \n    secret-key: \n    \n#########################################\n# knife4j configuration\n#########################################\nknife4j:\n  enable: true\n  production: false\n  basic:\n    enable: false\n    username: admin\n    password: 123456\n  setting:\n    enableOpenApi: false\n    enableSwaggerModels: false\n    enableFooter: false\n    enableFooterCustom: true\n    footerCustomContent: Apache License 2.0 | Copyright 2022-[SNOWY](https://www.xiaonuo.vip)\n\n# knife4j doc groups\nspringdoc:\n  default-flat-param-object: true\n  group-configs:\n    - group: SNOWY-PLUGIN-AUTH\n      display-name: SNOWY-PLUGIN-AUTH\n      packages-to-scan: vip.xiaonuo.auth\n    - group: SNOWY-PLUGIN-DEV\n      display-name: SNOWY-PLUGIN-DEV\n      packages-to-scan: vip.xiaonuo.dev\n    - group: SNOWY-PLUGIN-GEN\n      display-name: SNOWY-PLUGIN-GEN\n      packages-to-scan: vip.xiaonuo.gen\n    - group: SNOWY-PLUGIN-MOBILE\n      display-name: SNOWY-PLUGIN-MOBILE\n      packages-to-scan: vip.xiaonuo.mobile\n    - group: SNOWY-PLUGIN-SYS\n      display-name: SNOWY-PLUGIN-SYS\n      packages-to-scan: vip.xiaonuo.sys\n\n\n#########################################\n# snowy configuration\n#########################################\nsnowy:\n  config:\n    # common configuration\n    common:\n      backend-url: http://localhost:9101\n      file-url: http://localhost:9003/api/webapp\n\n# plugin dev-sms configuration\nsms-oa:\n  config-type: yaml\n  core-pool-size: 20\n  queue-capacity: 20\n  max-pool-size: 20', 'a4d5cb4fb646995632295b4adb72b5b5', '2010-05-05 00:00:00', '2026-03-08 14:02:15', NULL, '192.168.1.2', 'U', 'snowy-cloud-dev', '');
INSERT INTO `his_config_info` (`id`, `nid`, `data_id`, `group_id`, `app_name`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `op_type`, `tenant_id`, `encrypted_data_key`) VALUES (17, 2, 'snowy-web-app-prod.yaml', 'prod', '', '#########################################\n# server configuration\n#########################################\nserver:\n  port: 9101\n\n#########################################\n# spring profiles configuration\n#########################################\nspring:\n\n  #########################################\n  # multipart configuration\n  #########################################\n  servlet:\n    multipart:\n      max-request-size: 100MB\n      max-file-size: 100MB\n\n  #########################################\n  # mvc configuration\n  #########################################\n  mvc:\n    pathmatch:\n      matching-strategy: ant_path_matcher\n\n  #########################################\n  # main configuration\n  #########################################\n  main:\n    allow-circular-references: true\n\n  #########################################\n  # boot configuration\n  #########################################\n  boot:\n    admin:\n      client:\n        url: http://localhost:9001\n        instance:\n          # 默认使用的是主机名注册，改为使用ip注册\n          prefer-ip: true\n\n  #########################################\n  # cloud configuration\n  #########################################\n  cloud:\n    loadbalancer:\n      ribbon:\n        enabled: false\n      cache:\n        enabled: true\n        caffeine:\n          spec: initialCapacity=500,expireAfterWrite=5s\n    nacos:\n      discovery:\n        server-addr: ${spring.cloud.nacos.config.server-addr}\n        namespace: ${spring.cloud.nacos.config.namespace}\n        group: ${spring.cloud.nacos.config.group}\n        username: ${spring.cloud.nacos.config.username}\n        password: ${spring.cloud.nacos.config.password}\n\n  #########################################\n  # datasource configuration\n  #########################################\n\n  # mysql\n  datasource:\n    dynamic:\n      datasource:\n        master:\n          driver-class-name: com.mysql.cj.jdbc.Driver\n          url: jdbc:mysql://localhost:3306/snowy-cloud?useUnicode=true&characterEncoding=utf-8&useSSL=false&allowPublicKeyRetrieval=true&nullCatalogMeansCurrent=true&useInformationSchema=true&rewriteBatchedStatements=true\n          username: root\n          password: 123456\n      strict: true\n\n  # oracle\n#  datasource:\n#    dynamic:\n#      datasource:\n#        master:\n#          driver-class-name: oracle.jdbc.driver.OracleDriver\n#          url: jdbc:oracle:thin:@//127.0.0.1:1521/XE?remarksReporting=true\n#          username: SNOWY\n#          password: 12345678\n#      strict: true\n\n  # mssql\n#  datasource:\n#    dynamic:\n#      datasource:\n#        master:\n#          driver-class-name: com.microsoft.sqlserver.jdbc.SQLServerDriver\n#          url: jdbc:sqlserver://localhost:1433;DatabaseName=SNOWY\n#          username: sa\n#          password: 12345678\n#      strict: true\n\n  # dm database\n#  datasource:\n#    dynamic:\n#      datasource:\n#        master:\n#          driver-class-name: dm.jdbc.driver.DmDriver\n#          url: jdbc:dm://localhost:5236/SYSDBA\n#          username: SYSDBA\n#          password: SYSDBA\n#      strict: true\n\n  # kingbase database\n#  datasource:\n#    dynamic:\n#      datasource:\n#        master:\n#          driver-class-name: com.kingbase8.Driver\n#          url: jdbc:kingbase8://localhost:54321/snowy\n#          username: SYSTEM\n#          password: 123456\n#      strict: true\n\n      # druid global configuration\n      public-key: MFwwDQYJKoZIhvcNAQEBBQADSwAwSAJBAMWiTVtdXFVrgFHDDKELZM0SywkWY3KjugN90eY5Sogon1j8Y0ClPF7nx3FuE7pAeBKiv7ChIS0vvx/59WUpKmUCAwEAAQ==\n      druid:\n        initial-size: 10\n        max-active: 80\n        min-idle: 10\n        max-wait: 60000\n        pool-prepared-statements: true\n        max-pool-prepared-statement-per-connection-size: 20\n        validation-query-timeout: 2000\n        test-on-borrow: false\n        test-on-return: false\n        test-while-idle: true\n        time-between-eviction-runs-millis: 6000\n        min-evictable-idle-time-millis: 300000\n        filters: stat\n        break-after-acquire-failure: false\n\n    # druid monitor configuration\n    druid:\n      stat-view-servlet:\n        enabled: true\n        login-username: admin\n        login-password: 123456\n        allow: \"\"\n\n  #########################################\n  # jackson configuration\n  #########################################\n  jackson:\n    time-zone: GMT+8\n    date-format: yyyy-MM-dd HH:mm:ss\n    locale: zh_CN\n\n  #########################################\n  # redis configuration\n  #########################################\n  data:\n    redis:\n      database: 1\n      host: 127.0.0.1\n      port: 6379\n      password:\n      timeout: 10s\n      lettuce:\n        pool:\n          max-active: 800\n          max-wait: -1ms\n          max-idle: 10\n          min-idle: 0\n\n#########################################\n# 开放所有endpoint，实际生产根据自身需要开放，出于安全考虑不建议全部开放\n#########################################\nmanagement:\n  endpoints:\n    web:\n      exposure:\n        include: \"*\"\n    health:\n      show-details: \"ALWAYS\"\n\n#########################################\n# mybatis-plus configuration\n#########################################\nmybatis-plus:\n  configuration:\n    log-impl: org.apache.ibatis.logging.stdout.StdOutImpl\n  global-config:\n    banner: false\n    enable-sql-runner: true\n    db-config:\n      id-type: ASSIGN_ID\n      logic-delete-field: DELETE_FLAG\n      logic-delete-value: DELETED\n      logic-not-delete-value: NOT_DELETE\n  mapper-locations: classpath*:vip/xiaonuo/**/mapping/*.xml,com/bstek/**/mapping/*.xml\n  type-handlers-package: vip.xiaonuo.common.handler\n\n#########################################\n# easy-trans configuration\n#########################################\neasy-trans:\n  is-enable-redis: true\n  is-enable-global: true\n  is-enable-tile: true\n  is-enable-cloud: false\n\n#########################################\n# sa-token configuration\n#########################################\nsa-token:\n  token-name: token\n  timeout: 2592000\n  active-timeout: -1\n  is-concurrent: true\n  is-share: false\n  max-login-count: -1\n  token-style: random-32\n  is-log: false\n  is-print: false\n\n# sa-token alone-redis configuration\n  alone-redis:\n    database: 2\n    host: ${spring.data.redis.host}\n    port: ${spring.data.redis.port}\n    password: ${spring.data.redis.password}\n    timeout: ${spring.data.redis.timeout}\n    lettuce:\n      pool:\n        max-active: ${spring.data.redis.lettuce.pool.max-active}\n        max-wait: ${spring.data.redis.lettuce.pool.max-wait}\n        max-idle: ${spring.data.redis.lettuce.pool.max-idle}\n        min-idle: ${spring.data.redis.lettuce.pool.min-idle}\n\n  # sso configuration      \n  sso-client:\n    client: \n    auth-url: \n    signout-url: \n    push-url: \n    secret-key: \n    \n#########################################\n# knife4j configuration\n#########################################\nknife4j:\n  enable: true\n  production: false\n  basic:\n    enable: false\n    username: admin\n    password: 123456\n  setting:\n    enableOpenApi: false\n    enableSwaggerModels: false\n    enableFooter: false\n    enableFooterCustom: true\n    footerCustomContent: Apache License 2.0 | Copyright 2022-[SNOWY](https://www.xiaonuo.vip)\n\n# knife4j doc groups\nspringdoc:\n  default-flat-param-object: true\n  group-configs:\n    - group: SNOWY-PLUGIN-AUTH\n      display-name: SNOWY-PLUGIN-AUTH\n      packages-to-scan: vip.xiaonuo.auth\n    - group: SNOWY-PLUGIN-DEV\n      display-name: SNOWY-PLUGIN-DEV\n      packages-to-scan: vip.xiaonuo.dev\n    - group: SNOWY-PLUGIN-GEN\n      display-name: SNOWY-PLUGIN-GEN\n      packages-to-scan: vip.xiaonuo.gen\n    - group: SNOWY-PLUGIN-MOBILE\n      display-name: SNOWY-PLUGIN-MOBILE\n      packages-to-scan: vip.xiaonuo.mobile\n    - group: SNOWY-PLUGIN-SYS\n      display-name: SNOWY-PLUGIN-SYS\n      packages-to-scan: vip.xiaonuo.sys\n\n\n#########################################\n# snowy configuration\n#########################################\nsnowy:\n  config:\n    # common configuration\n    common:\n      backend-url: http://localhost:9101\n      file-url: http://localhost:9003/api/webapp\n\n# plugin dev-sms configuration\nsms-oa:\n  config-type: yaml\n  core-pool-size: 20\n  queue-capacity: 20\n  max-pool-size: 20', 'a4d5cb4fb646995632295b4adb72b5b5', '2010-05-05 00:00:00', '2026-03-08 14:02:29', NULL, '192.168.1.2', 'U', 'snowy-cloud-prod', '');
